`35-41`: **Fix potential off-by-one error in version check.**

The version comparison `>=` includes version 4.16.0, but the comment suggests it should be skipped "for 4.16.0 or later". This could lead to inconsistent behavior.

Apply this diff to fix the version check:

```diff
-if (moqAssembly != null && moqAssembly.Version >= new Version(4, 16, 0))
+if (moqAssembly?.Version > new Version(4, 15, 999))
```

---

`35-35`: **Add null check before accessing Name property.**

The `FirstOrDefault` could return null, and accessing the `Name` property would throw a `NullReferenceException`.

Apply this diff to add null check:

```diff
-AssemblyIdentity? moqAssembly = context.Compilation.ReferencedAssemblyNames.FirstOrDefault(a => a.Name.Equals("Moq", StringComparison.OrdinalIgnoreCase));
+AssemblyIdentity? moqAssembly = context.Compilation.ReferencedAssemblyNames.FirstOrDefault(a => a?.Name?.Equals("Moq", StringComparison.OrdinalIgnoreCase) == true);
```

</blockquote></details>
<details>
<summary>src/Analyzers/SetupShouldBeUsedOnlyForOverridableMembersAnalyzer.cs (3)</summary><blockquote>

`35-86`: **Refactor long method to improve maintainability.**

The method is marked with `SuppressMessage` for being too long. It should be refactored into smaller, more focused methods.

Apply this diff to refactor the method:

```diff
-    [SuppressMessage("Design", "MA0051:Method is too long", Justification = "Should be fixed. Ignoring for now to avoid additional churn as part of larger refactor.")]
     private static void AnalyzeInvocation(OperationAnalysisContext context)
     {
-        if (context.Operation is not IInvocationOperation invocationOperation)
+        if (!TryGetInvocationOperation(context, out var invocationOperation))
         {
             return;
         }

-        SemanticModel? semanticModel = invocationOperation.SemanticModel;
+        if (!TryGetSemanticModel(invocationOperation, out var semanticModel))
+        {
+            return;
+        }

-        if (semanticModel == null)
+        var knownSymbols = new MoqKnownSymbols(semanticModel.Compilation);
+        if (!IsMoqSetupMethodInvocation(invocationOperation, knownSymbols))
         {
             return;
         }

-        MoqKnownSymbols knownSymbols = new(semanticModel.Compilation);
-        IMethodSymbol targetMethod = invocationOperation.TargetMethod;
+        if (!TryGetMockedMemberSymbol(invocationOperation, out var mockedMemberSymbol))
+        {
+            return;
+        }

-        // 1. Check if the invoked method is a Moq Setup method
-        if (!targetMethod.IsMoqSetupMethod(knownSymbols))
+        if (IsValidMockedMember(mockedMemberSymbol, knownSymbols))
         {
             return;
         }

-        // 2. Attempt to locate the member reference from the Setup expression argument.
-        //    Typically, Moq setup calls have a single lambda argument like x => x.SomeMember.
-        //    We'll extract that member reference or invocation to see whether it is overridable.
-        ISymbol? mockedMemberSymbol = TryGetMockedMemberSymbol(invocationOperation);
-        if (mockedMemberSymbol == null)
+        ReportDiagnostic(context, invocationOperation);
+    }
+
+    private static bool TryGetInvocationOperation(OperationAnalysisContext context, out IInvocationOperation invocationOperation)
+    {
+        invocationOperation = context.Operation as IInvocationOperation;
+        return invocationOperation != null;
+    }
+
+    private static bool TryGetSemanticModel(IInvocationOperation invocationOperation, out SemanticModel semanticModel)
+    {
+        semanticModel = invocationOperation.SemanticModel;
+        return semanticModel != null;
+    }
+
+    private static bool IsMoqSetupMethodInvocation(IInvocationOperation invocationOperation, MoqKnownSymbols knownSymbols)
+    {
+        return invocationOperation.TargetMethod.IsMoqSetupMethod(knownSymbols);
+    }
+
+    private static bool IsValidMockedMember(ISymbol mockedMemberSymbol, MoqKnownSymbols knownSymbols)
+    {
+        if (mockedMemberSymbol.ContainingType?.TypeKind == TypeKind.Interface)
         {
-            return;
+            return true;
         }

-        // 3. Skip if the symbol is part of an interface, those are always "overridable".
-        if (mockedMemberSymbol.ContainingType?.TypeKind == TypeKind.Interface)
-        {
-            return;
-        }
+        return IsPropertyOrMethod(mockedMemberSymbol, knownSymbols);
+    }

-        // 4. Check if symbol is a property or method, and if it is overridable or is returning a Task (which Moq allows).
-        if (IsPropertyOrMethod(mockedMemberSymbol, knownSymbols))
-        {
-            return;
-        }
-
-        // 5. If we reach here, the member is neither overridable nor allowed by Moq
-        //    So we report the diagnostic.
-        //
-        // NOTE: The location is on the invocationOperation, which is fairly broad
+    private static void ReportDiagnostic(OperationAnalysisContext context, IInvocationOperation invocationOperation)
+    {
         Diagnostic diagnostic = invocationOperation.Syntax.CreateDiagnostic(Rule);
         context.ReportDiagnostic(diagnostic);
     }
```

