    const auto size = p.size();
    if (size != 2) return false;

    auto it = p.begin();
    if (*it != -1) return false;

    auto next = std::next(it);
    if (!next->IsUnivariable()) return false;

    auto& var = next->as<Variable>();
    if (var == va) {
        isNormalizedPolynomial = true;
        return true;
    }
    return false;
}
```

